#define THREADS 256
#define WIDTH 16  
#define HEIGHT 16 
#define ETA 0.3f       
#define MOMENTUM 0.3f  

#ifndef _BACKPROP_CUDA_KERNEL_H_
#define _BACKPROP_CUDA_KERNEL_H_
#define WM(i, j)   weight_matrix[(j) + (i) * WIDTH]

#include <omp.h>
#include <math.h>
#include <stdio.h>
#include <stdlib.h>

float squash(float x)
{
    return (1.0f / (1.0f + expf(-x)));
}

void bpnn_layerforward(float *l1, float *l2, float **conn, int n1, int n2)
{
    float sum;
    int j, k;

    l1[0] = 1.0f;
    #pragma omp parallel for private(j, k) schedule(static)
    for (j = 1; j <= n2; j++) {
        sum = 0.0f;
        for (k = 0; k <= n1; k++) {
            sum += conn[k][j] * l1[k];
        }
        l2[j] = squash(sum);
    }
}

void bpnn_output_error(float *delta, float *target, float *output, int nj, float *err)  
{
    int j;
    float o, t, errsum;
    errsum = 0.0f;
    for (j = 1; j <= nj; j++) {
        o = output[j];
        t = target[j];
        delta[j] = o * (1.0f - o) * (t - o);
        errsum += (delta[j] > 0.0f) ? delta[j] : -delta[j];
    }
    *err = errsum;
}

void bpnn_hidden_error(float *delta_h,   
                       int nh, 
                       float *delta_o, 
                       int no, 
                       float **who, 
                       float *hidden, 
                       float *err)
{
    int j, k;
    float h, sum, errsum;

    errsum = 0.0f;
    for (j = 1; j <= nh; j++) {
        h = hidden[j];
        sum = 0.0f;
        for (k = 1; k <= no; k++) {
            sum += delta_o[k] * who[j][k];
        }
        delta_h[j] = h * (1.0f - h) * sum;
        errsum += (delta_h[j] > 0.0f) ? delta_h[j] : -delta_h[j];
    }
    *err = errsum;
}

void bpnn_adjust_weights(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw)
{
    float new_dw;
    int k, j;
    ly[0] = 1.0f;

    #pragma omp parallel for private(j, k, new_dw) schedule(static)
    for (j = 1; j <= ndelta; j++) {
        for (k = 0; k <= nly; k++) {
            new_dw = ((ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[k][j]));
            w[k][j] += new_dw;
            oldw[k][j] = new_dw;
        }
    }
}

void bpnn_initialize(int seed)
{
    printf("Random number generator seed: %d\n", seed);
    srand(seed);
}

void bpnn_free(BPNN *net)
{
    int n1, n2, i;

    n1 = net->input_n;
    n2 = net->hidden_n;

    free(net->input_units);
    free(net->hidden_units);
    free(net->output_units);

    free(net->hidden_delta);
    free(net->output_delta);
    free(net->target);

    for (i = 0; i <= n1; i++) {
        free(net->input_weights[i]);
        free(net->input_prev_weights[i]);
    }
    free(net->input_weights);
    free(net->input_prev_weights);

    for (i = 0; i <= n2; i++) {
        free(net->hidden_weights[i]);
        free(net->hidden_prev_weights[i]);
    }
    free(net->hidden_weights);
    free(net->hidden_prev_weights);

    free(net);
}

void bpnn_layerforward_omp(float *input_cuda,
	                  float *output_hidden_cuda,
					  float *input_hidden_cuda,
					  float *hidden_partial_sum,
					  int in,
					  int hid) 
{
    int num_blocks = in / HEIGHT;
    int by, ty, tx;

    #pragma omp parallel private(by, ty, tx)
    {
        float input_node[HEIGHT];
        float weight_matrix[HEIGHT * WIDTH];

        #pragma omp for schedule(static)
        for (by = 0; by < num_blocks; by++) {
            for (ty = 0; ty < HEIGHT; ty++) {
                int index_in = HEIGHT * by + ty + 1;
                input_node[ty] = input_cuda[index_in];
            }

            for (ty = 0; ty < HEIGHT; ty++) {
                for (tx = 0; tx < WIDTH; tx++) {
                    int index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 ) ;  
                    weight_matrix[ty * WIDTH + tx] =  input_hidden_cuda[index];
                }
            }

            for (ty = 0; ty < HEIGHT; ty++) {
                for (tx = 0; tx < WIDTH; tx++) {
                    weight_matrix[ty * WIDTH + tx]= weight_matrix[ty * WIDTH + tx] * input_node[ty];
                }
            }

            for (int i = 1 ; i <= HEIGHT ; i=i*2){
                int power_two = i; 
                for (ty = 0; ty < HEIGHT; ty++) {
                    for (tx = 0; tx < WIDTH; tx++) {
                        if(ty % power_two == 0 && (ty + power_two/2) < HEIGHT) {
                            weight_matrix[ty * WIDTH + tx] = weight_matrix[ty * WIDTH + tx] + weight_matrix[(ty + power_two/2)* WIDTH + tx];
                        }
                    }
                }
            }

            for (ty = 0; ty < HEIGHT; ty++) {
                for (tx = 0; tx < WIDTH; tx++) {
                    int index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 ) ;  
                    input_hidden_cuda[index] =  weight_matrix[ty * WIDTH + tx];
                }
            }

            if (omp_get_thread_num() == 0) {
                for (ty = 0; ty < HEIGHT; ty++) {
                    hidden_partial_sum[by * hid + ty] = weight_matrix[ty * WIDTH + 0];
                }
            }
        }
    }
}

void bpnn_adjust_weights_omp(float * delta,   
										 int hid,         
										float * ly,      
										 int in,          
										float * w,       
										float * oldw)  									
{
    int num_blocks = in / HEIGHT;
    int by, ty, tx;

    #pragma omp parallel private(by, ty, tx)
    {
        #pragma omp for schedule(static)
        for (by = 0; by < num_blocks; by++) {
            for (ty = 0; ty < HEIGHT; ty++) {
                for (tx = 0; tx < WIDTH; tx++) {
                    int index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 ) ;  
                    int index_y = HEIGHT * by + ty + 1;
                    int index_x = tx + 1;

                    float new_dw = ((ETA * delta[index_x] * ly[index_y]) + (MOMENTUM * oldw[index]));
                    w[index] += new_dw;
                    oldw[index] = new_dw;
                }
            }
        }

        if (omp_get_thread_num() == 0) {
            for (int index_x = 1; index_x <= WIDTH; index_x++) {
                w[index_x] += ((ETA * delta[index_x]) + (MOMENTUM * oldw[index_x]));
                oldw[index_x] = ((ETA * delta[index_x]) + (MOMENTUM * oldw[index_x]));
            }
        }
    }
}

#endif
